// Declarable: LOAN-2b's exactly-one-tie check runs only for region parameters of a confined RESULT type.
// gut returns unit, so no check runs; 'u ties to zero borrow-mode parameters, so per LOAN-1 e enters holding NO loans.
fn gut<'t,'u>(t: &uniq 't table<K,V>, e: own entry<'u>) -> unit {
  t.insert(k2, v2);   // inside gut L(t)={} -> legal; insert may rehash (the draft's own P2 rationale)
  e.fill(v);          // consumes e; writes through the now-stale interior pointer -> UAF
}

fn main() {
  let t: table<K,V> = table.new();
  let e = t.entry(k);       // LOAN-2b: L(t)={(e,unique)}, src(e)={t:unique}
  gut(&uniq t, own e);      // LOAN-3 exception: the single call consumes e by own, so its &uniq borrow of t is permitted;
                            // LOAN-7 is silent: e's type carries 'u, the borrow-mode arg is at 't (distinct declared regions);
                            // LOAN-6: t is borrowed, not moved; LOAN-5: consume e -> L(t)={}. Every rule passes.
}

// Declarable: result region 't occurs on exactly one borrow-mode parameter (t, mode &) -> LOAN-2b passes.
fn launder<'t>(t: &'t table<K,V>, e: own entry<'t>) -> entry<'t> {
  return e;                    // TOK-3: 't is caller-supplied -> legal. Entry state L(t)={(e,shared)} per LOAN-1
}                              // (strength = parameter mode &), and no rule requires a callee to end with L(t) empty.

fn main() {
  let t: table<K,V> = table.new();
  let e = t.entry(k);             // L(t)={(e,unique)} — unique-interior token
  let e2 = launder(&t, own e);    // LOAN-3 exception (consumes e, & of t allowed); LOAN-7: src(e)={t} = B at 't -> passes,
                                  // because LOAN-7 checks brand identity, never strength; consume e, then LOAN-2b reissues
                                  // from the SIGNATURE: tying parameter mode is & -> L(t)={(e2,shared)}, src(e2)={t:shared}
  let c = t.range(lo, hi);        // LOAN-4: all-shared, further shared issue permitted -> L(t)={(e2,shared),(c,shared)}
  let n1 = c.next();              // live shared cursor
  e2.fill(v1);                    // statement takes no borrow of t (it consumes e2 only) -> LOAN-3/4 never inspect it ->
                                  // ACCEPTED: writes the table's interior while shared cursor c and shared readers are live
  let n2 = c.next();              // cursor observes interior mutation under an all-shared regime
}

fn main() {                            // block region 'B
  let t1: table<K,V> = table.new();
  let a = t1.entry(k0);                // a: entry<'B> (TOK-3: owned source -> enclosing block region); L(t1)={(a,unique)}
  a.fill(v0);                          // consume a -> a consumed, L(t1)={}
  let t2: table<K,V> = table.new();    // declared AFTER binding a; same block -> same region 'B
  let e2 = t2.entry(k2);               // e2: entry<'B>; L(t2)={(e2,unique)}
  a = e2;                              // TOK-4: destination a is a consumed binding of identical type entry<'B> -> legal move;
                                       // held-loan entries rename -> L(t2)={(a,unique)}, src(a)={t2:unique}
}                                       // scope end, reverse binding order: e2 (moved-from, nothing), then t2 is DROPPED while
                                        // L(t2)={(a,unique)}, then a is auto-consumed (LOAN-5): its drop obligation (release/abandon)
                                        // runs against the freed table -> use-after-free

confined struct Env<'e> { t: &'e table<K,V> }   // TOK-1: legal user confined struct (P6 uses exactly this)

fn main() {
  let tbl: table<K,V> = table.new();
  let env = Env { t: &tbl };        // LOAN-2a: L(tbl)={(env,shared)}
  match env {                        // TOK-2 permits a confined scrutinee; destructure semantics are UNDEFINED
    Env { t: tb } => {               // tb: a multi-statement borrow binding extracted from a stored borrow field —
                                     // an object kind the pre-M1 kernel never had (no stored borrows existed)
      // Natural affine reading: the match consumed env, and LOAN-1's exhaustive update list
      // (creation / own-consumption / TOK-4 binding moves / scope end) covers none of this,
      // so the plausible implementation clears (env,shared) -> L(tbl)={}
      let tbl2 = own tbl;            // LOAN-6 sees an empty loan set -> move permitted
      let v = tb.get(k);             // read through a borrow whose referent's binding was moved -> UAF
    }
  }
}

// P6's own body signature, per the draft:
fn body(chunk: &uniq 'c chunk<i64>, env: &'e Env<'e>) reads('e) writes('c) { ... }
// LOAN-1: 'each confined parameter holds a loan on each borrow-mode parameter its region parameters tie it to.'
// env's region parameter 'e ties to the borrow-mode parameter whose declared region is 'e — which is env itself.
// So at entry L(env)={(env,shared)}: a self-loan. Harmless today (LOAN-4 then permits only & uses of env,
// LOAN-6 pins a binding that is a borrow parameter anyway), but the tie relation now contains cycles,
// and nothing says whether a borrow-mode parameter OF CONFINED TYPE counts as a tie target for other
// parameters/results (e.g. split<'c>(c2: &'c range_view<'c>) -> subrange<'c>, a token minted from a token).
